from itertools import product

def find_even_numbers(digits):
    even_numbers = set()
    for p in product(digits, repeat=3):
        num = int(''.join(map(str, p)))
        if num >= 100 and num % 2 == 0:
            even_numbers.add(num)
    return sorted(list(even_numbers))

