def find_even_numbers(digits):
    unique_numbers = set()
    even_digits = [digit for digit in digits if digit % 2 == 0]
    if not even_digits:
        return []

    for first_digit, second_digit, third_digit in product(digits, repeat=3):
        if first_digit != 0 and third_digit in even_digits:
            unique_numbers.add(int(f"{first_digit}{second_digit}{third_digit}"))

    return sorted(list(unique_numbers))

