def find_all_permutations(digits):
    if not digits:
        return []

    def backtrack(combination, next_digits):
        if len(combination) == 3:
            output.append(int(''.join(map(str, combination))))
            return
        for i in range(len(next_digits)):
            new_combination = combination + [next_digits[i]]
            new_next_digits = next_digits[:i] + next_digits[i + 1:]
            backtrack(new_combination, new_next_digits)

    output = []
    backtrack([], digits)
    return sorted(output)

