def find_permutations(digits):
    def backtrack(start, path):
        if len(path) == 3:
            result.append(int(''.join(map(str, path))))
            return
        for i in range(len(digits)):
            if i > 0 and digits[i] == digits[i-1]:
                continue
            path.append(digits[i])
            backtrack(i + 1, path)
            path.pop()

    digits.sort()
    result = []
    backtrack(0, [])
    return sorted(result)

def find_permutations_with_duplicates(digits):
    def backtrack(start, path):
        if len(path) == 3:
            result.add(int(''.join(map(str, path))))
            return
        for i in range(len(digits)):
            path.append(digits[i])
            backtrack(i + 1, path)
            path.pop()

    result = set()
    backtrack(0, [])
    return sorted(list(result))

def find_all_permutations(digits):
    if len(set(digits)) == len(digits):
        return find_permutations(digits)
    else:
        return find_permutations_with_duplicates(digits)

